        GREETINGS_AND_WELL_MET_I_AM_A_VOIDWATCH                               = 11178,  -- Greetings and well met. I am a Voidwatch scientist charged with researching the potential uses of atmacite.
        THOSE_WHO_POSSESS_MAY_COME_TO_ME_TO                                   = 11179,  -- Those who possess % may come to me to have their hard-won atmacite infused. Stratum abyssite also falls within my domain, so present to me any whose properties you wish to have analyzed.
        AH_I_M_ALSO_AUTHORIZED_TO_TELEPORT_FOLK                               = 11180,  -- Ah, I'm also authorized to teleport folk to operation sites. Quite versatile, aren't I?
        I_BEG_OF_YOU_FRIEND_LEND_US_YOUR                                      = 11181,  -- I beg of you, friend. Lend us your stout sword arm in the fight to protect Vana'diel from the Voidwalker threat.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_HAVE                                 = 11182,  -- What will you do? Nothing for now. Have stratum abyssite examined. Request teleportation. Analyze atmacite. Ask about atmacite. Ask about atmacite enrichment.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_INFUSED_2                            = 11183,  -- What will you do? Nothing for now. Infused: % (lv.#) Infused: % (lv.#) Infused: % (lv.#) Purge atmacite. Infuse atmacite. Enrich atmacite.
