        OH_MY_SUCH_A_MAGNIFICENT_DISPLAY_OF_EVOLUTION                         = 11221,  -- Oh my, such a magnificent display of evolution! Leaves absolutely nothing to be desired!
        WHY_YES_THIS_STONE_IS_SHOWING_THE_INITIAL                             = 11222,  -- Why yes, this stone is showing the initial signs of evolution. It appears there's still room for growth, however.
        HMMM_I_FEAR_THIS_STONE_S_GROWTH_HAS                                   = 11223,  -- Hmmm... I fear this stone's growth has been interrupted. Were you to find a catalyst of sorts, perhaps it could still evolve further?
        HMMM_I_M_AFRAID_THE_STONE_ISN_T_2                                     = 11224,  -- Hmmm... I'm afraid the stone isn't exhibiting any signs of growth. Perhaps a catalyst of sorts could help to spur along the process?
        HOW_CURIOUS_I_VE_NOT_SEEN_A_STONE                                     = 11225,  -- How curious. I've not seen a stone like this before. Wherever did you find it?
        YOUR_HAS_EVOLVED_INTO                                                 = 11226,  -- Your % has evolved into %!
        SUPPLY_ME_WITH_THE_CRUOR_NECESSARY_AND_I                              = 11227,  -- Supply me with the # cruor necessary, and I shall gladly teleport you to an operation site of your choosing.
