        BEFORE_YOU_LIES_A_SURVIVAL_GUIDE_PENNED_BY_2                          = 12285,  -- Before you lies a survival guide penned by the Servicemen's Mutual Aid Network. It touches on such topics as teleportation and battle records.
        WHAT_CHAPTER_WILL_YOU_READ_NONE_TELEPORTATION_ASSISTANCE              = 12286,  -- What chapter will you read? None. Teleportation Assistance. Field Support. Other mysteries.
        THE_METICULOUSLY_ILLUMINATED_TEXT_WITHIN_EXPLAINS_THAT_ADVENTURERS    = 12287,  -- The meticulously illuminated text within explains that adventurers may travel to the location of any previous books visited after paying a sum of gil or the requisite amount of tabs.
        NO_OTHER_SURVIVAL_GUIDE_LOCATIONS_HAVE_BEEN_RECORDED                  = 12288,  -- No other survival guide locations have been recorded. Visiting another one would certainly alleviate this issue.
        WHERE_WILL_YOU_TRAVEL_NOWHERE_PREVIOUS_PAGE_NEXT                      = 12289,  -- Where will you travel? Nowhere. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Previous page. Next page.
